 const CATPPUCCIN_MACCHIATO_PINK = "#f5bde6";
@@ -9,22 +11,26 @@ const CATPPUCCIN_MACCHIATO_RED = "#ed8796";
 const WIDGET_KEY = "answer-summary:final";
 const MAX_FILE_ROWS = 8;
 const MAX_TEXT_BYTES = 5 * 1024 * 1024;
+const MAX_MYERS_EDIT_DISTANCE = 2_000;
+const UTF8_DECODER = new TextDecoder("utf-8", { fatal: true });

 type FileSnapshot =
-	| { kind: "text"; content: string | null }
-	| { kind: "skipped"; reason: string };
+	| { kind: "missing" }
+	| { kind: "text"; content: string }
+	| { kind: "opaque"; reason: string; fingerprint: string | null };

 type FileStats = {
 	path: string;
 	name: string;
 	status: "added" | "deleted" | "modified";
-	added: number;
-	removed: number;
+	added: number | null;
+	removed: number | null;
 };

-const beforeByPath = new Map<string, FileSnapshot>();
-const touchedPaths = new Set<string>();
-let activeAnswerStart: number | null = null;
+type SummaryState = {
+	beforeByPath: Map<string, FileSnapshot>;
+	touchedPaths: Set<string>;
+};

 function hexToRgb(hex: string): [number, number, number] {
 	const h = hex.replace("#", "");
@@ -53,13 +59,32 @@ function formatElapsed(ms: number): string {

 function readSnapshot(path: string): FileSnapshot {
 	try {
-		if (!existsSync(path)) return { kind: "text", content: null };
 		const stat = statSync(path);
-		if (!stat.isFile()) return { kind: "skipped", reason: "not a file" };
-		if (stat.size > MAX_TEXT_BYTES) return { kind: "skipped", reason: "large file" };
-		return { kind: "text", content: readFileSync(path, "utf8") };
+		const metadataFingerprint = `${stat.dev}:${stat.ino}:${stat.size}:${stat.mtimeMs}`;
+		if (!stat.isFile()) {
+			return { kind: "opaque", reason: "not a regular file", fingerprint: metadataFingerprint };
+		}
+		if (stat.size > MAX_TEXT_BYTES) {
+			return { kind: "opaque", reason: "file is too large", fingerprint: metadataFingerprint };
+		}
+
+		const bytes = readFileSync(path);
+		const contentFingerprint = createHash("sha256").update(bytes).digest("hex");
+		if (bytes.includes(0)) {
+			return { kind: "opaque", reason: "binary file", fingerprint: contentFingerprint };
+		}
+		try {
+			return { kind: "text", content: UTF8_DECODER.decode(bytes) };
+		} catch {
+			return { kind: "opaque", reason: "non-UTF-8 file", fingerprint: contentFingerprint };
+		}
 	} catch (error) {
-		return { kind: "skipped", reason: error instanceof Error ? error.message : String(error) };
+		if ((error as NodeJS.ErrnoException).code === "ENOENT") return { kind: "missing" };
+		return {
+			kind: "opaque",
+			reason: error instanceof Error ? error.message : String(error),
+			fingerprint: null,
+		};
 	}
 }

@@ -70,7 +95,7 @@ function splitLines(content: string): string[] {
 	return lines;
 }

-function shortestInsertDeleteScriptLength(beforeLines: string[], afterLines: string[]): number {
+function shortestInsertDeleteScriptLength(beforeLines: string[], afterLines: string[]): number | null {
 	let beforeStart = 0;
 	let afterStart = 0;
 	let beforeEnd = beforeLines.length;
@@ -99,12 +124,13 @@ function shortestInsertDeleteScriptLength(beforeLines: string[], afterLines: str
 	if (newCount === 0) return oldCount;

 	const max = oldCount + newCount;
-	const offset = max + 1;
-	const furthest = new Int32Array(max * 2 + 3);
+	const distanceLimit = Math.min(max, MAX_MYERS_EDIT_DISTANCE);
+	const offset = distanceLimit + 1;
+	const furthest = new Int32Array(distanceLimit * 2 + 3);
 	furthest.fill(-1);
 	furthest[offset + 1] = 0;

-	for (let distance = 0; distance <= max; distance++) {
+	for (let distance = 0; distance <= distanceLimit; distance++) {
 		for (let diagonal = -distance; diagonal <= distance; diagonal += 2) {
 			const index = offset + diagonal;
 			const goDown = diagonal === -distance || (diagonal !== distance && furthest[index - 1] < furthest[index + 1]);
@@ -121,15 +147,19 @@ function shortestInsertDeleteScriptLength(beforeLines: string[], afterLines: str
 		}
 	}

-	return max;
+	return null;
 }

-function diffLineStats(before: string | null, after: string | null): { added: number; removed: number } {
+function diffLineStats(before: string, after: string): { added: number; removed: number } | null {
 	if (before === after) return { added: 0, removed: 0 };

-	const beforeLines = splitLines(before ?? "");
-	const afterLines = splitLines(after ?? "");
+	const beforeLines = splitLines(before);
+	const afterLines = splitLines(after);
 	const distance = shortestInsertDeleteScriptLength(beforeLines, afterLines);
+	if (distance === null) return null;
+
+	// A final-newline-only edit has a zero line-sequence distance but is still a real change.
+	if (distance === 0) return { added: 1, removed: 1 };

 	return {
 		added: Math.max(0, Math.round((distance - beforeLines.length + afterLines.length) / 2)),
@@ -149,8 +179,15 @@ function absoluteToolPath(ctx: ExtensionContext, input: unknown): string | null
 	return path === null ? null : resolve(ctx.cwd, path);
 }

-function displayPath(path: string, _cwd: string): string {
-	return basename(path) || path;
+function sanitizeDisplayText(text: string): string {
+	return text
+		.replace(/\x1b\][^\x07]*(?:\x07|\x1b\\)/g, "")
+		.replace(/\x1b\[[0-?]*[ -/]*[@-~]/g, "")
+		.replace(/[\u0000-\u001f\u007f-\u009f]/g, "�");
+}
+
+function displayPath(path: string): string {
+	return sanitizeDisplayText(basename(path) || path);
 }

 function pathParts(path: string, cwd: string): string[] {
@@ -172,38 +209,68 @@ function disambiguateDuplicateNames(rows: FileStats[], cwd: string) {

 		const partsByPath = new Map(group.map((row) => [row.path, pathParts(row.path, cwd)]));
 		const maxDepth = Math.max(...Array.from(partsByPath.values(), (parts) => parts.length));
+		let disambiguated = false;

 		for (let depth = 2; depth <= maxDepth; depth++) {
-			const names = group.map((row) => (partsByPath.get(row.path) ?? [row.name]).slice(-depth).join("/"));
+			const names = group.map((row) =>
+				sanitizeDisplayText((partsByPath.get(row.path) ?? [row.name]).slice(-depth).join("/")),
+			);
 			if (new Set(names).size !== group.length) continue;

 			for (let i = 0; i < group.length; i++) group[i].name = names[i];
+			disambiguated = true;
 			break;
 		}
+
+		if (!disambiguated) {
+			for (let i = 0; i < group.length; i++) {
+				group[i].name = `${sanitizeDisplayText(group[i].path)} #${i + 1}`;
+			}
+		}
 	}
 }

-function rememberBefore(path: string) {
-	if (!beforeByPath.has(path)) beforeByPath.set(path, readSnapshot(path));
+function rememberBefore(state: SummaryState, path: string) {
+	if (!state.beforeByPath.has(path)) state.beforeByPath.set(path, readSnapshot(path));
 }

 function clearSummary(ctx: ExtensionContext) {
 	ctx.ui.setWidget(WIDGET_KEY, undefined);
 }

-function collectFileStats(ctx: ExtensionContext): FileStats[] {
+function collectFileStats(state: SummaryState, ctx: ExtensionContext): FileStats[] {
 	const rows: FileStats[] = [];

-	for (const path of touchedPaths) {
-		const before = beforeByPath.get(path);
+	for (const path of state.touchedPaths) {
+		const before = state.beforeByPath.get(path);
+		if (!before) continue;
 		const after = readSnapshot(path);
-		if (!before || before.kind !== "text" || after.kind !== "text") continue;
-
-		const { added, removed } = diffLineStats(before.content, after.content);
-		if (added === 0 && removed === 0) continue;
-
-		const status = before.content === null ? "added" : after.content === null ? "deleted" : "modified";
-		rows.push({ path, name: displayPath(path, ctx.cwd), status, added, removed });
+		const beforeExists = before.kind !== "missing";
+		const afterExists = after.kind !== "missing";
+
+		if (!beforeExists && !afterExists) continue;
+		if (before.kind === "text" && after.kind === "text" && before.content === after.content) continue;
+		if (
+			before.kind === "opaque" &&
+			after.kind === "opaque" &&
+			before.fingerprint !== null &&
+			before.fingerprint === after.fingerprint
+		) continue;
+
+		const status = !beforeExists ? "added" : !afterExists ? "deleted" : "modified";
+		const beforeText = before.kind === "text" ? before.content : before.kind === "missing" ? "" : null;
+		const afterText = after.kind === "text" ? after.content : after.kind === "missing" ? "" : null;
+		const stats = beforeText !== null && afterText !== null
+			? diffLineStats(beforeText, afterText)
+			: null;
+
+		rows.push({
+			path,
+			name: displayPath(path),
+			status,
+			added: stats?.added ?? null,
+			removed: stats?.removed ?? null,
+		});
 	}

 	disambiguateDuplicateNames(rows, ctx.cwd);
