 	return rows;
 }

-function renderSummary(ctx: ExtensionContext, elapsedMs: number): string[] {
-	const rows = collectFileStats(ctx);
+function renderSummary(state: SummaryState, ctx: ExtensionContext, elapsedMs: number): string[] {
+	const rows = collectFileStats(state, ctx);
 	const elapsed = colorHex(CATPPUCCIN_MACCHIATO_PINK, formatElapsed(elapsedMs));

 	if (rows.length === 0) return [elapsed];

-	const totalAdded = rows.reduce((sum, row) => sum + row.added, 0);
-	const totalRemoved = rows.reduce((sum, row) => sum + row.removed, 0);
-	const firstLine = [
+	const totalAdded = rows.reduce((sum, row) => sum + (row.added ?? 0), 0);
+	const totalRemoved = rows.reduce((sum, row) => sum + (row.removed ?? 0), 0);
+	const uncounted = rows.filter((row) => row.added === null || row.removed === null).length;
+	const firstLineParts = [
 		elapsed,
 		ctx.ui.theme.fg("dim", `${rows.length} ${rows.length === 1 ? "file" : "files"}`),
 		ctx.ui.theme.fg("success", `+${totalAdded}`),
 		ctx.ui.theme.fg("error", `-${totalRemoved}`),
-	].join(" ");
+	];
+	if (uncounted > 0) firstLineParts.push(ctx.ui.theme.fg("dim", `${uncounted} uncounted`));
+	const firstLine = firstLineParts.join(" ");

 	const detailLines = rows.slice(0, MAX_FILE_ROWS).map((row) => {
 		const styledName = row.status === "added"
@@ -235,9 +305,13 @@ function renderSummary(ctx: ExtensionContext, elapsedMs: number): string[] {
 				? colorHex(CATPPUCCIN_MACCHIATO_RED, row.name)
 				: colorHex(CATPPUCCIN_MACCHIATO_BLUE, row.name);

-		if (row.status === "added") return `${styledName} ${ctx.ui.theme.fg("success", `+${row.added}`)}`;
-		if (row.status === "deleted") return `${styledName} ${ctx.ui.theme.fg("error", `-${row.removed}`)}`;
-		return `${styledName} ${ctx.ui.theme.fg("success", `+${row.added}`)} ${ctx.ui.theme.fg("error", `-${row.removed}`)}`;
+		if (row.status === "added") {
+			return `${styledName} ${ctx.ui.theme.fg("success", `+${row.added ?? "?"}`)}`;
+		}
+		if (row.status === "deleted") {
+			return `${styledName} ${ctx.ui.theme.fg("error", `-${row.removed ?? "?"}`)}`;
+		}
+		return `${styledName} ${ctx.ui.theme.fg("success", `+${row.added ?? "?"}`)} ${ctx.ui.theme.fg("error", `-${row.removed ?? "?"}`)}`;
 	});

 	if (rows.length > MAX_FILE_ROWS) {
@@ -248,21 +322,32 @@ function renderSummary(ctx: ExtensionContext, elapsedMs: number): string[] {
 }

 export default function (pi: ExtensionAPI) {
+	const state: SummaryState = {
+		beforeByPath: new Map(),
+		touchedPaths: new Set(),
+	};
+	let activeAnswerStart: number | null = null;
+
 	pi.on("session_start", async (_event, ctx) => {
+		activeAnswerStart = null;
+		state.beforeByPath.clear();
+		state.touchedPaths.clear();
 		clearSummary(ctx);
 	});

 	pi.on("agent_start", async (_event, ctx) => {
+		// Preserve the same summary across automatic retries, compaction, and queued follow-ups.
+		if (activeAnswerStart !== null) return;
 		activeAnswerStart = Date.now();
-		beforeByPath.clear();
-		touchedPaths.clear();
+		state.beforeByPath.clear();
+		state.touchedPaths.clear();
 		clearSummary(ctx);
 	});

 	pi.on("tool_call", async (event, ctx) => {
 		if (event.toolName !== "edit" && event.toolName !== "write") return;
 		const path = absoluteToolPath(ctx, event.input);
-		if (path !== null) rememberBefore(path);
+		if (path !== null) rememberBefore(state, path);
 	});

 	pi.on("tool_result", async (event, ctx) => {
@@ -272,20 +357,23 @@ export default function (pi: ExtensionAPI) {
 		const path = absoluteToolPath(ctx, event.input);
 		if (path === null) return;

-		rememberBefore(path);
-		touchedPaths.add(path);
+		rememberBefore(state, path);
+		state.touchedPaths.add(path);
 	});

-	pi.on("agent_end", async (_event, ctx) => {
-		const elapsedMs = activeAnswerStart === null ? 0 : Date.now() - activeAnswerStart;
+	pi.on("agent_settled", async (_event, ctx) => {
+		if (activeAnswerStart === null || !ctx.isIdle()) return;
+		const elapsedMs = Date.now() - activeAnswerStart;
+		ctx.ui.setWidget(WIDGET_KEY, renderSummary(state, ctx, elapsedMs), { placement: "aboveEditor" });
 		activeAnswerStart = null;
-		ctx.ui.setWidget(WIDGET_KEY, renderSummary(ctx, elapsedMs), { placement: "aboveEditor" });
+		state.beforeByPath.clear();
+		state.touchedPaths.clear();
 	});

 	pi.on("session_shutdown", async (_event, ctx) => {
 		activeAnswerStart = null;
-		beforeByPath.clear();
-		touchedPaths.clear();
+		state.beforeByPath.clear();
+		state.touchedPaths.clear();
 		clearSummary(ctx);
 	});
 }

