 35	function hexToRgb(hex: string): [number, number, number] {
 36		const h = hex.replace("#", "");
 37		return [
 38			parseInt(h.slice(0, 2), 16),
 39			parseInt(h.slice(2, 4), 16),
 40			parseInt(h.slice(4, 6), 16),
 41		];
 42	}
