 47	}
 48	
 49	function formatElapsed(ms: number): string {
 50		const totalSeconds = Math.max(0, Math.floor(ms / 1000));
 51		const hours = Math.floor(totalSeconds / 3600);
 52		const minutes = Math.floor((totalSeconds % 3600) / 60);
 53		const seconds = totalSeconds % 60;
 54	
 55		if (hours > 0) return `${hours}h${minutes.toString().padStart(2, "0")}m`;
 56		if (minutes > 0) return `${minutes}m${seconds.toString().padStart(2, "0")}s`;
 57		return `${seconds}s`;
 58	}
 59	
 60	function readSnapshot(path: string): FileSnapshot {
 61		try {
 62			const stat = statSync(path);
 63			const metadataFingerprint = `${stat.dev}:${stat.ino}:${stat.size}:${stat.mtimeMs}`;
 64			if (!stat.isFile()) {
 65				return { kind: "opaque", reason: "not a regular file", fingerprint: metadataFingerprint };
 66			}
 67			if (stat.size > MAX_TEXT_BYTES) {
 68				return { kind: "opaque", reason: "file is too large", fingerprint: metadataFingerprint };
 69			}
 70	
 71			const bytes = readFileSync(path);
 72			const contentFingerprint = createHash("sha256").update(bytes).digest("hex");
 73			if (bytes.includes(0)) {
 74				return { kind: "opaque", reason: "binary file", fingerprint: contentFingerprint };
 75			}
 76			try {
 77				return { kind: "text", content: UTF8_DECODER.decode(bytes) };
 78			} catch {
 79				return { kind: "opaque", reason: "non-UTF-8 file", fingerprint: contentFingerprint };
 80			}
 81		} catch (error) {
 82			if ((error as NodeJS.ErrnoException).code === "ENOENT") return { kind: "missing" };
 83			return {
 84				kind: "opaque",
 85				reason: error instanceof Error ? error.message : String(error),
 86				fingerprint: null,
 87			};
 88		}
 89	}
 90	
 91	function splitLines(content: string): string[] {
 92		if (content.length === 0) return [];
 93		const lines = content.split("\n");
 94		if (lines[lines.length - 1] === "") lines.pop();
 95		return lines;
 96	}
 97	
 98	function shortestInsertDeleteScriptLength(beforeLines: string[], afterLines: string[]): number | null {
 99		let beforeStart = 0;
100		let afterStart = 0;
101		let beforeEnd = beforeLines.length;
102		let afterEnd = afterLines.length;
103	
104		while (beforeStart < beforeEnd && afterStart < afterEnd && beforeLines[beforeStart] === afterLines[afterStart]) {
105			beforeStart++;
106			afterStart++;
107		}
108	
109		while (
110			beforeStart < beforeEnd &&
111			afterStart < afterEnd &&
112			beforeLines[beforeEnd - 1] === afterLines[afterEnd - 1]
113		) {
114			beforeEnd--;
115			afterEnd--;
116		}
117	
118		const oldLines = beforeLines.slice(beforeStart, beforeEnd);
119		const newLines = afterLines.slice(afterStart, afterEnd);
120		const oldCount = oldLines.length;
121		const newCount = newLines.length;
122	
123		if (oldCount === 0) return newCount;
124		if (newCount === 0) return oldCount;
125	
126		const max = oldCount + newCount;
127		const distanceLimit = Math.min(max, MAX_MYERS_EDIT_DISTANCE);
128		const offset = distanceLimit + 1;
129		const furthest = new Int32Array(distanceLimit * 2 + 3);
130		furthest.fill(-1);
131		furthest[offset + 1] = 0;
132	
133		for (let distance = 0; distance <= distanceLimit; distance++) {
134			for (let diagonal = -distance; diagonal <= distance; diagonal += 2) {
135				const index = offset + diagonal;
136				const goDown = diagonal === -distance || (diagonal !== distance && furthest[index - 1] < furthest[index + 1]);
137				let x = goDown ? furthest[index + 1] : furthest[index - 1] + 1;
138				let y = x - diagonal;
139	
140				while (x < oldCount && y < newCount && oldLines[x] === newLines[y]) {
141					x++;
142					y++;
143				}
144	
145				furthest[index] = x;
146				if (x >= oldCount && y >= newCount) return distance;
147			}
148		}
149	
150		return null;
151	}
152	
153	function diffLineStats(before: string, after: string): { added: number; removed: number } | null {
154		if (before === after) return { added: 0, removed: 0 };
155	
156		const beforeLines = splitLines(before);
157		const afterLines = splitLines(after);
158		const distance = shortestInsertDeleteScriptLength(beforeLines, afterLines);
159		if (distance === null) return null;
160	
161		// A final-newline-only edit has a zero line-sequence distance but is still a real change.
162		if (distance === 0) return { added: 1, removed: 1 };
163	
164		return {
165			added: Math.max(0, Math.round((distance - beforeLines.length + afterLines.length) / 2)),
166			removed: Math.max(0, Math.round((distance + beforeLines.length - afterLines.length) / 2)),
167		};
168	}
169	
170	function toolPath(input: unknown): string | null {
171		if (!input || typeof input !== "object") return null;
172		const value = (input as { path?: unknown; file_path?: unknown }).path ??
173			(input as { path?: unknown; file_path?: unknown }).file_path;
174		return typeof value === "string" && value.length > 0 ? value : null;
175	}
176	
177	function absoluteToolPath(ctx: ExtensionContext, input: unknown): string | null {
178		const path = toolPath(input);
179		return path === null ? null : resolve(ctx.cwd, path);
180	}
181	
182	function sanitizeDisplayText(text: string): string {
183		return text
184			.replace(/\x1b\][^\x07]*(?:\x07|\x1b\\)/g, "")
185			.replace(/\x1b\[[0-?]*[ -/]*[@-~]/g, "")
186			.replace(/[\u0000-\u001f\u007f-\u009f]/g, "�");
187	}
188	
189	function displayPath(path: string): string {
190		return sanitizeDisplayText(basename(path) || path);
191	}
192	
193	function pathParts(path: string, cwd: string): string[] {
194		const rel = relative(cwd, path);
195		const displayPath = rel && !rel.startsWith("..") && !isAbsolute(rel) ? rel : path;
196		return displayPath.split(/[\\/]+/).filter(Boolean);
197	}
198	
199	function disambiguateDuplicateNames(rows: FileStats[], cwd: string) {
200		const byName = new Map<string, FileStats[]>();
201		for (const row of rows) {
202			const group = byName.get(row.name) ?? [];
203			group.push(row);
204			byName.set(row.name, group);
205		}
206	
207		for (const group of byName.values()) {
208			if (group.length <= 1) continue;
209	
210			const partsByPath = new Map(group.map((row) => [row.path, pathParts(row.path, cwd)]));
211			const maxDepth = Math.max(...Array.from(partsByPath.values(), (parts) => parts.length));
212			let disambiguated = false;
213	
214			for (let depth = 2; depth <= maxDepth; depth++) {
215				const names = group.map((row) =>
216					sanitizeDisplayText((partsByPath.get(row.path) ?? [row.name]).slice(-depth).join("/")),
217				);
218				if (new Set(names).size !== group.length) continue;
219	
220				for (let i = 0; i < group.length; i++) group[i].name = names[i];
221				disambiguated = true;
222				break;
223			}
224	
225			if (!disambiguated) {
226				for (let i = 0; i < group.length; i++) {
227					group[i].name = `${sanitizeDisplayText(group[i].path)} #${i + 1}`;
228				}
229			}
230		}
231	}
232	
233	function rememberBefore(state: SummaryState, path: string) {
234		if (!state.beforeByPath.has(path)) state.beforeByPath.set(path, readSnapshot(path));
235	}
236	
237	function clearSummary(ctx: ExtensionContext) {
238		ctx.ui.setWidget(WIDGET_KEY, undefined);
239	}
240	
241	function collectFileStats(state: SummaryState, ctx: ExtensionContext): FileStats[] {
242		const rows: FileStats[] = [];
243	
244		for (const path of state.touchedPaths) {
245			const before = state.beforeByPath.get(path);
246			if (!before) continue;
247			const after = readSnapshot(path);
248			const beforeExists = before.kind !== "missing";
249			const afterExists = after.kind !== "missing";
250	
251			if (!beforeExists && !afterExists) continue;
252			if (before.kind === "text" && after.kind === "text" && before.content === after.content) continue;
253			if (
254				before.kind === "opaque" &&
255				after.kind === "opaque" &&
256				before.fingerprint !== null &&
257				before.fingerprint === after.fingerprint
258			) continue;
259	
260			const status = !beforeExists ? "added" : !afterExists ? "deleted" : "modified";
261			const beforeText = before.kind === "text" ? before.content : before.kind === "missing" ? "" : null;
262			const afterText = after.kind === "text" ? after.content : after.kind === "missing" ? "" : null;
263			const stats = beforeText !== null && afterText !== null
264				? diffLineStats(beforeText, afterText)
265				: null;
266	
267			rows.push({
268				path,
269				name: displayPath(path),
270				status,
271				added: stats?.added ?? null,
272				removed: stats?.removed ?? null,
273			});
274		}
275	
276		disambiguateDuplicateNames(rows, ctx.cwd);
277	
278		const statusOrder = { modified: 0, added: 1, deleted: 2 } as const;
279		rows.sort((a, b) => statusOrder[a.status] - statusOrder[b.status] || a.name.localeCompare(b.name));
280		return rows;
281	}
282	
283	function renderSummary(state: SummaryState, ctx: ExtensionContext, elapsedMs: number): string[] {
284		const rows = collectFileStats(state, ctx);
285		const elapsed = colorHex(CATPPUCCIN_MACCHIATO_PINK, formatElapsed(elapsedMs));
286	
287		if (rows.length === 0) return [elapsed];
288	
289		const totalAdded = rows.reduce((sum, row) => sum + (row.added ?? 0), 0);
290		const totalRemoved = rows.reduce((sum, row) => sum + (row.removed ?? 0), 0);
291		const uncounted = rows.filter((row) => row.added === null || row.removed === null).length;
292		const firstLineParts = [
293			elapsed,
294			ctx.ui.theme.fg("dim", `${rows.length} ${rows.length === 1 ? "file" : "files"}`),
295			ctx.ui.theme.fg("success", `+${totalAdded}`),
296			ctx.ui.theme.fg("error", `-${totalRemoved}`),
297		];
298		if (uncounted > 0) firstLineParts.push(ctx.ui.theme.fg("dim", `${uncounted} uncounted`));
299		const firstLine = firstLineParts.join(" ");
300	
301		const detailLines = rows.slice(0, MAX_FILE_ROWS).map((row) => {
302			const styledName = row.status === "added"
303				? colorHex(CATPPUCCIN_MACCHIATO_GREEN, row.name)
304				: row.status === "deleted"
305					? colorHex(CATPPUCCIN_MACCHIATO_RED, row.name)
306					: colorHex(CATPPUCCIN_MACCHIATO_BLUE, row.name);
307	
308			if (row.status === "added") {
309				return `${styledName} ${ctx.ui.theme.fg("success", `+${row.added ?? "?"}`)}`;
310			}
311			if (row.status === "deleted") {
312				return `${styledName} ${ctx.ui.theme.fg("error", `-${row.removed ?? "?"}`)}`;
313			}
314			return `${styledName} ${ctx.ui.theme.fg("success", `+${row.added ?? "?"}`)} ${ctx.ui.theme.fg("error", `-${row.removed ?? "?"}`)}`;
315		});
316	
317		if (rows.length > MAX_FILE_ROWS) {
318			detailLines.push(ctx.ui.theme.fg("dim", `… ${rows.length - MAX_FILE_ROWS} more`));
319		}
320	
321		return [firstLine, ...detailLines];
322	}
